def can_jump(nums):
    n = len(nums)

    def helper(i):
        if i >= n - 1:
            return True
        for step in range(nums[i], 0, -1):
            if helper(i + step):
                return True
        return False

    return helper(0)

def can_jump(nums):
    n = len(nums)
    farthest = 0
    for i, x in enumerate(nums):
        if i > farthest:
            return False
        farthest = max(farthest, i + x)
        if farthest >= n - 1:
            return True
    return True
